#!/usr/bin/env node
'use strict';

const fs = require('fs');
const path = require('path');

function fail(msg) {
  console.error(`[bundle-lua] ${msg}`);
  process.exit(1);
}

function parseArgs(argv) {
  const out = {
    root: '.',
    entry: 'logger.lua',
    out: 'dist/logger.bundle.lua'
  };

  for (let i = 2; i < argv.length; i += 1) {
    const arg = argv[i];
    if (arg === '--root') out.root = argv[++i];
    else if (arg === '--entry') out.entry = argv[++i];
    else if (arg === '--out') out.out = argv[++i];
    else if (arg === '--help' || arg === '-h') {
      console.log('Usage: node scripts/bundle-lua.js --entry logger.lua --out dist/logger.bundle.lua --root .');
      process.exit(0);
    } else {
      fail(`Unknown arg: ${arg}`);
    }
  }

  return out;
}

function toPosix(p) {
  return p.replace(/\\/g, '/');
}

function withoutLuaExt(p) {
  return p.endsWith('.lua') ? p.slice(0, -4) : p;
}

function normalizeModuleId(fromModuleId, rawRequire, rootDir) {
  const cleaned = rawRequire.replace(/\\/g, '/');

  let id;
  if (cleaned.startsWith('./') || cleaned.startsWith('../')) {
    const baseDir = path.posix.dirname(fromModuleId);
    id = path.posix.normalize(path.posix.join(baseDir, cleaned));
  } else {
    id = path.posix.normalize(cleaned);
  }

  id = withoutLuaExt(id);

  const abs = path.resolve(rootDir, `${id}.lua`);
  if (!fs.existsSync(abs)) {
    fail(`Module not found: require("${rawRequire}") from "${fromModuleId}" -> expected ${abs}`);
  }

  return id;
}

function bundle({ root, entry, out }) {
  const rootDir = path.resolve(process.cwd(), root);
  const entryAbs = path.resolve(rootDir, entry);
  if (!fs.existsSync(entryAbs)) fail(`Entry file not found: ${entryAbs}`);

  const entryId = withoutLuaExt(toPosix(path.relative(rootDir, entryAbs)));
  const moduleMap = new Map();

  function visit(moduleId) {
    if (moduleMap.has(moduleId)) return;

    const absPath = path.resolve(rootDir, `${moduleId}.lua`);
    if (!fs.existsSync(absPath)) fail(`Missing file for module "${moduleId}": ${absPath}`);

    let code = fs.readFileSync(absPath, 'utf8').replace(/^\uFEFF/, '');

    const requireRegex = /require\s*\(\s*(["'])([^"']+)\1\s*\)/g;
    code = code.replace(requireRegex, (_full, quote, reqPath) => {
      const normalizedId = normalizeModuleId(moduleId, reqPath, rootDir);
      visit(normalizedId);
      return `require(${quote}${normalizedId}${quote})`;
    });

    moduleMap.set(moduleId, code);
  }

  visit(entryId);

  const ordered = Array.from(moduleMap.entries());
  const moduleChunks = ordered.map(([id, code]) => {
    return `__modules[${JSON.stringify(id)}] = function(require)\n${code}\nend`;
  });

  const header = [
    '-- AUTO-GENERATED FILE. DO NOT EDIT DIRECTLY.',
    '-- Generated by scripts/bundle-lua.js',
    `-- Entry: ${entryId}`,
    '',
    'local __modules = {}',
    ''
  ].join('\n');

  const runtime = [
    '',
    'local __cache = {}',
    'local function require(name)',
    '    local cached = __cache[name]',
    '    if cached ~= nil then return cached end',
    '    local loader = __modules[name]',
    '    if not loader then error("module not found: " .. tostring(name), 2) end',
    '    local value = loader(require)',
    '    if value == nil then value = true end',
    '    __cache[name] = value',
    '    return value',
    'end',
    '',
    `return require(${JSON.stringify(entryId)})`,
    ''
  ].join('\n');

  const output = `${header}${moduleChunks.join('\n\n')}${runtime}`;
  const outAbs = path.resolve(rootDir, out);
  fs.mkdirSync(path.dirname(outAbs), { recursive: true });
  fs.writeFileSync(outAbs, output, 'utf8');

  console.log(`[bundle-lua] Wrote ${outAbs}`);
  console.log(`[bundle-lua] Modules bundled: ${ordered.length}`);
}

bundle(parseArgs(process.argv));
